// Full slice-level verification
const colonial = document.getElementById('periodo-colonial');
const cards = colonial.querySelectorAll('.event-card');
const images = colonial.querySelectorAll('.card-image img');
const placeholders = colonial.querySelectorAll('.event-card--placeholder');
const timeline = colonial.querySelector('.colonial-timeline');
const certezaCards = colonial.querySelectorAll('[data-certeza]');
const hechoCards = colonial.querySelectorAll('[data-certeza="hecho"]');
const opinionCards = colonial.querySelectorAll('[data-certeza="opinion"]');
const rumorCards = colonial.querySelectorAll('[data-certeza="rumor"]');
const citeElements = colonial.querySelectorAll('cite');
const opinionAuthors = colonial.querySelectorAll('.card-opinion__author');
const rumorOrigins = colonial.querySelectorAll('.card-rumor__origin');

// Image checks
const imageResults = Array.from(images).map(img => ({
  alt: img.alt,
  loaded: img.naturalWidth > 0,
  lazy: img.loading === 'lazy',
  wikimedia: img.src.includes('wikimedia.org')
}));

// Timeline checks  
const timelineRevealed = timeline ? timeline.classList.contains('reveal--visible') : false;
const timelineMarkers = timeline ? timeline.querySelectorAll('.colonial-timeline__marker').length : 0;

JSON.stringify({
  totalCards: cards.length,
  totalImages: images.length,
  placeholderCards: placeholders.length,
  certezaCards: certezaCards.length,
  hechoCount: hechoCards.length,
  opinionCount: opinionCards.length,
  rumorCount: rumorCards.length,
  citeCount: citeElements.length,
  opinionAuthors: opinionAuthors.length,
  rumorOrigins: rumorOrigins.length,
  timelineExists: !!timeline,
  timelineRevealed,
  timelineMarkers,
  imageResults
}, null, 2)

